<script setup lang="ts">
import {computed,onMounted,reactive,ref} from 'vue';import {api,type Envelope} from '@/api';import {ElMessage} from 'element-plus';import {useAuthStore} from '@/stores/auth';
const auth=useAuthStore(),employee=computed(()=>auth.user?.role==='EMPLOYEE'),canManage=computed(()=>auth.can('task:manage')),canReview=computed(()=>auth.can('task:review'));const tasks=ref<any[]>([]),assignments=ref<any[]>([]),employees=ref<any[]>([]),batches=ref<any[]>([]),stations=ref<any[]>([]),dialog=ref(false),selected=ref<any>(),files=ref<any[]>([]),history=ref<any[]>([]);const task=reactive({title:'',description:'',requirements:'',deadline:''}),assign=reactive<any>({taskId:null,employeeIds:[],batchId:null,stationId:null}),submit=reactive({content:''}),review=reactive<any>({decision:'APPROVE',comment:'',score:80});
async function load(){tasks.value=(await api.get<any,Envelope<any[]>>('/tasks')).data;assignments.value=(await api.get<any,Envelope<any[]>>('/assignments')).data;if(canManage.value){employees.value=(await api.get<any,Envelope<any>>('/employees',{params:{size:100}})).data.records;batches.value=(await api.get<any,Envelope<any[]>>('/batches')).data;stations.value=(await api.get<any,Envelope<any[]>>('/stations')).data}}async function create(){await api.post('/tasks',task);ElMessage.success('任务已创建');load()}async function doAssign(){const r=await api.post<any,Envelope<number>>('/assignments/assign',assign);ElMessage.success(`已分配 ${r.data} 人`);load()}async function open(row:any){selected.value=row;history.value=(await api.get<any,Envelope<any[]>>(`/assignments/${row.id}/submissions`)).data;dialog.value=true}async function doSubmit(){const fd=new FormData();fd.append('content',submit.content);files.value.forEach(x=>fd.append('files',x.raw));await api.post(`/assignments/${selected.value.id}/submissions`,fd);dialog.value=false;load()}async function doReview(){await api.post(`/submissions/${history.value[0].id}/review`,review);dialog.value=false;load()}onMounted(load);
</script>
<template><div class="page"><div class="page-head"><h2>闯关任务</h2></div><el-row v-if="canManage" :gutter="16"><el-col :md="12"><el-card><template #header>创建任务</template><el-input v-model="task.title" placeholder="标题"/><el-input v-model="task.description" type="textarea" placeholder="说明"/><el-date-picker v-model="task.deadline" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/><el-button type="primary" @click="create">创建</el-button></el-card></el-col><el-col :md="12"><el-card><template #header>分配任务</template><el-select v-model="assign.taskId"><el-option v-for="x in tasks" :key="x.id" :label="x.title" :value="x.id"/></el-select><el-select v-model="assign.employeeIds" multiple filterable><el-option v-for="x in employees" :key="x.id" :label="x.name" :value="x.id"/></el-select><el-button type="primary" @click="doAssign">分配</el-button></el-card></el-col></el-row><el-card><template #header>{{employee?'我的任务':'任务完成情况'}}</template><el-table :data="assignments"><el-table-column v-if="!employee" prop="employee_name" label="员工"/><el-table-column prop="title" label="任务"/><el-table-column prop="deadline" label="截止时间"/><el-table-column prop="status" label="状态"/><el-table-column prop="final_score" label="培训方评分"/><el-table-column label="操作"><template #default="s"><el-button v-if="employee&&['NOT_SUBMITTED','RETURNED'].includes(s.row.status)" link @click="open(s.row)">提交</el-button><el-button v-if="canReview&&s.row.status==='PENDING_REVIEW'" link @click="open(s.row)">审核</el-button></template></el-table-column></el-table></el-card><el-dialog v-model="dialog" :title="employee?'提交成果':'审核成果'"><template v-if="employee"><el-input v-model="submit.content" type="textarea"/><el-upload multiple :auto-upload="false" :on-change="(_f:any,list:any[])=>files=list"><el-button>选择文件</el-button></el-upload></template><template v-else><p v-if="history.length">{{history[0].content}}</p><el-radio-group v-model="review.decision"><el-radio value="APPROVE">通过</el-radio><el-radio value="RETURN">退回</el-radio></el-radio-group><el-input-number v-if="review.decision==='APPROVE'" v-model="review.score" :min="0" :max="100"/><el-input v-model="review.comment" type="textarea"/></template><template #footer><el-button type="primary" @click="employee?doSubmit():doReview()">确认</el-button></template></el-dialog></div></template>
